class ListNode:
    def __init__(self, key, val):
        self.key = key
        self.val = val
        self.freq = 1
        self.prev = self.next = None

class LinkedList:
    def __init__(self):
        self.left = ListNode(0, 0)
        self.right = ListNode(0, 0)
        self.left.next, self.right.prev = self.right, self.left
        self.map = {}
    def length(self):
        return len(self.map)
    def pushRight(self, node):
        prev, nxt = self.right.prev, self.right
        prev.next = nxt.prev = node
        node.prev, node.next = prev, nxt
        self.map[node.key] = node
    def pop(self, node):
        prev, nxt = node.prev, node.next
        prev.next, nxt.prev = nxt, prev
        del self.map[node.key]
    def popLeft(self):
        res = self.left.next
        self.pop(self.left.next)
        return res

import collections
class LFUCache:
    def __init__(self, capacity: int):
        self.cap = capacity
        self.lfuCount = 0
        self.valMap = {}
        self.countMap = collections.defaultdict(LinkedList)
    def counter(self, key):
        node = self.valMap[key]
        self.countMap[node.freq].pop(node)
        if self.lfuCount == node.freq and not self.countMap[node.freq].length():
            self.lfuCount += 1
        node.freq += 1
        self.countMap[node.freq].pushRight(node)
    def get(self, key: int) -> int:
        if key not in self.valMap:
            return -1
        self.counter(key)
        return self.valMap[key].val
    def put(self, key: int, value: int) -> None:
        if self.cap == 0:
            return
        if key not in self.valMap and len(self.valMap) == self.cap:
            res = self.countMap[self.lfuCount].popLeft()
            del self.valMap[res.key]
        if key in self.valMap:
            self.valMap[key].val = value
            self.counter(key)
        else:
            node = ListNode(key, value)
            self.valMap[key] = node
            self.countMap[1].pushRight(node)
            self.lfuCount = 1

